input.command:
for L in /workspace/compose_wt/outputs/s5_gear_iter4/compose.log /workspace/compose_wt/outputs/s5_sonnet_hands/compose.log /workspace/compose_wt/outputs/s5_gear_iter3/compose.log /workspace/compose_wt/outputs/s5_gear_iter1/compose.log /workspace/compose_wt/outputs/s5_gear_iter1_pinned/compose.log /workspace/compose_wt/outputs/s5_gear_round_iter1/compose.log /workspace/POLARIS/outputs/s5_gear/compose_iter2.log; do
 h=$(grep -c 'HTTP/1.1 429' "$L" 2>/dev/null||echo 0); p=$(grep -c 'HTTP Request: POST https://openrouter.ai' "$L" 2>/dev/null||echo 0);
 first=$(grep -m1 -oE '^2026-[0-9:, T-]+' "$L"|head -1); last=$(grep -oE '^2026-[0-9:, T-]+' "$L"|tail -1);
 echo "$L | 429=$h | openrouter_POSTs=$p | window: $first -> $last"; done
